    if (!g_obj_allocate)
        g_obj_allocate = caml_named_value("cd_obj_allocate");
    if (!g_obj_allocate) return -1;

    value v_result = caml_callback(*g_obj_allocate, Val_unit);
    return Int_val(v_result);
}

