		static int oa_reg = 0;
		if (!oa_reg) {
			oa_reg = 1;
			cd_ox_register_obj_allocate_effects(
				/* fetch: [num_objects, highest, highest_ever, is_d2, free_obj_list_entry, obj_types...] */
				[](int32_t* out, int* out_len) {
					out[0] = num_objects;
