	for (i = 0; i <= Highest_object_index; i++) {
		if ((objp->type != OBJ_NONE) && (!(objp->flags & OF_SHOULD_BE_DEAD))) {
			object_move_one(objp);
		}
		objp++;
	}
#else
	i = 0;	//kill warning
#endif

//	check_duplicate_objects();
//	remove_incorrect_objects();

}


